/**
 * Passport Help Content
 * AUTO-GENERATED from UK_Property_Passport_Education_Content.pdf
 * Re-generate: python prisma/extract_help.py
 *
 * Format:
 *   Seller guidance: plain paragraphs separated by \n
 *   Buyer guidance : paragraphs + ## Section Headers + • bullet lines
 *   HelpDrawer.vue renders ## headers and • bullets with styled formatting.
 */

export interface HelpContent {
  sellerGuidance: string;
  buyerGuidance: string;
  disclaimer?: string;
  helpVideoUrl?: string;
}

/** Convert a question title to a URL/key slug (must match seed.ts logic). */
export function toSlug(title: string): string {
  return title
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "_")
    .replace(/^_+|_+$/g, "");
}

